小程序以验证C/C++内存管理的差异（写的不是很严谨，仅为主题，分别在redhat 5.6 x86_64 + gcc-4.9.2，windows 7 x64 + gcc-4.9.2 编译运行通过）： #include &lt;iostream&gt;#include &lt;typeinfo&gt;#include &lt;stdlib.h&gt;#include &lt;stdio.h&gt;void t_cpu() { #define print_type(t) std::cout &lt;&lt; &#34;Size of &#34; &lt;&lt; #t &lt;&lt; &#34;: &#34; &lt;&lt; sizeof(t) &lt;&lt; std::endl print_type(char); print_type(unsigned char); print_type(short); print_type(unsigned short); print_type(int); print_type(unsigned int); print_type(size_t); print_type(long); print_type(unsigned long); print_type(long long); print_type(unsigned long long); print_type(float); print_type(double); print_type(long double); print_type(void*); } class __T { public: int _1; int _2; __T(){ _1 = 1; _2 = 2; } ~__T(){ printf(&#34;~&#34;); } void init() { _1 = 7; _2 = 8; } void test() { _1 += _2; } }; void t_new(size_t sl) { __T *pchar = new __T[sl]; size_t *psize = (size_t*)(((char*)pchar)-sizeof(size_t)); printf(&#34;
Test new and delete 
size: %ld pchar: %p psize: %p *psize: %ld 
&#34;, sl, pchar, psize, *psize); delete []pchar; printf(&#34;
&#34;); } void t_malloc(size_t sl) { printf(&#34;
Test malloc and free 
size of class __T: %ld 
&#34;, sizeof(class __T)); __T *pchar = (__T *)malloc(sl * sizeof(class __T)); size_t *psize = (size_t*)(((char*)pchar)-sizeof(size_t)); printf(&#34;size: %ld pchar: %p psize: %p *psize: %ld 
&#34;, sl, pchar, psize, *psize); free(pchar); } void t_new_free(size_t sl) { __T *pchar = new __T[sl]; size_t *psize = (size_t*)(((char*)pchar)-sizeof(size_t)); printf(&#34;
Test new and free 
size: %ld pchar: %p psize: %p *psize: %ld 
&#34;, sl, pchar, psize, *psize); //delete []pchar; for (__T *t = pchar; t &lt; pchar + sl; ++t) { t-&gt;~__T(); } free(psize); printf(&#34;
&#34;); } void t_malloc_delete(size_t sl) { printf(&#34;
Test malloc and delete 
size of class __T: %ld 
&#34;, sizeof(class __T)); size_t *psize = (size_t *)malloc(sl * sizeof(class __T) + sizeof(size_t)); __T *pchar = (__T*)(((char*)psize)+sizeof(size_t)); *psize = sl; //for (__T *t = pchar; t &lt; pchar + sl; ++t) { // t-&gt;init(); //} printf(&#34;size: %ld pchar: %p psize: %p *psize: %ld 
&#34;, sl, pchar, psize, *psize); delete [] pchar; printf(&#34;
&#34;); } int main() { t_cpu(); t_new(48); t_malloc(32); t_new_free(16); t_malloc_delete(8); return 0; } 输出（redhat）：
